.modal {
  display: none;
  position: fixed;
  z-index: 999;
  right: 0;
  top: 0;
  width: 100%;
  height: 100%;
  overflow: auto;
  background-color: rgba(0, 0, 0, 0.4);
}

.modal-content {
  margin: 15% auto;
  background-color: #fefefe;
  border: 1px solid #888;
  width: 80%;
  padding: 20px;
  box-shadow: 0 5px 10px rgba(0, 0, 0, .3);
  border-radius: 10px;
}

.col-lg-9 {
  width: 75%;
  float: left;
}

.modal-content .aws-search-form-wrapper {
  display: block;
  margin: 0 auto;
  width: 100%;
  max-width: 500px;
}

.modal-content .aws-search-form-wrapper form {
  margin-top: 20px;
}
